package service.strategies;

import service.strategies.ILabelStrategy;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class SimpleLayoutStrategy implements ILabelStrategy {
    private final String text;
    private final String sector;
    private final int quantity;

    public SimpleLayoutStrategy(String text, String sector, int quantity) {
        this.text = text;
        this.sector = sector;
        this.quantity = quantity;
    }

    @Override
    public String generateZpl() {
        StringBuilder zpl = new StringBuilder();

        String nomeCompleto = this.text.toUpperCase().trim();
        String infoSetor = (this.sector != null && !this.sector.isEmpty()) ? this.sector.toUpperCase() : "GERAL";

        // LĂ“GICA DE DIRETORIA: Se for GRUPO VISTA, nĂŁo adiciona o prefixo "VISTA - "
        String textoRodape;
        if (infoSetor.equals("GRUPO VISTA")) {
            textoRodape = "GRUPO VISTA";
        } else {
            textoRodape = "VISTA - " + infoSetor;
        }

        // Filtro de conectivos para nĂŁo embolar (MARCOS SOUZA em vez de MARCOS DE SOUZA)
        List<String> conectivos = Arrays.asList("DE", "DA", "DO", "DAS", "DOS");
        String[] todasPartes = nomeCompleto.split("\\s+");
        List<String> nomesSignificativos = new ArrayList<>();
        for (String p : todasPartes) {
            if (!conectivos.contains(p)) {
                nomesSignificativos.add(p);
            }
        }

        for (int i = 0; i < quantity; i++) {
            zpl.append("^XA\n^CI28\n^PW480\n^LL240\n");

            // 1. LOGO FIXA (X=355)
            zpl.append("^FO355,65^GFA,1800,1800,15,^FS\n");

            // 2. LAYOUT DO NOME
            if (nomesSignificativos.size() >= 2) {
                // Nome em duas linhas (Ex: AELSON / TEIXEIRA)
                zpl.append("^FO20,65^A0N,55,55^FB330,1,0,L,0^FD").append(nomesSignificativos.get(0)).append("^FS\n");
                zpl.append("^FO20,120^A0N,45,45^FB330,1,0,L,0^FD").append(nomesSignificativos.get(1)).append("^FS\n");
                // RodapĂ© ajustado (Sem o prefixo se for Grupo Vista)
                zpl.append("^FO20,185^A0N,28,28^FB330,1,0,L,0^FD").append(textoRodape).append("^FS\n");
            } else {
                // Nome em uma linha (Ex: EDUARDO)
                zpl.append("^FO20,95^A0N,75,75^FB330,1,0,L,0^FD").append(nomeCompleto).append("^FS\n");
                // RodapĂ© ajustado
                zpl.append("^FO20,180^A0N,30,30^FB330,1,0,L,0^FD").append(textoRodape).append("^FS\n");
            }

            zpl.append("^XZ\n");
        }
        return zpl.toString();
    }
}